const workflows = ($('RC Get Workflows').first().json.data || []);
const executions = ($input.first().json.data || []);

const lastRunMap = {};
executions.forEach(e => {
  if (e.workflowId && (!lastRunMap[e.workflowId] || new Date(e.startedAt) > new Date(lastRunMap[e.workflowId]))) {
    lastRunMap[e.workflowId] = e.startedAt;
  }
});

const active = workflows.filter(w => w.active);
const inactive = workflows.filter(w => !w.active);
const now = Date.now();
const twentyFourHAgo = now - 24 * 60 * 60 * 1000;

const activeEnriched = active.map(w => ({
  name: w.name,
  lastRun: lastRunMap[w.id] || null,
  ranToday: lastRunMap[w.id] ? new Date(lastRunMap[w.id]).getTime() > twentyFourHAgo : false
}));

return [{json: {
  activeNames: active.map(w => w.name),
  inactiveNames: inactive.map(w => w.name),
  activeEnriched,
  totalActive: active.length,
  totalInactive: inactive.length
}}];

const d = $input.first().json;
const now = new Date();

const prompt = `You are generating fun, personality-driven morning check-in messages for an AI office team. Each workflow is a digital employee with a unique character and job role.

TODAY: ${now.toLocaleDateString('en-GB', {weekday:'long', day:'numeric', month:'long'})}

ACTIVE employees CHECKED IN to the office today:
${d.activeNames.map((n, i) => `${i+1}. ${n}`).join('\n')}

INACTIVE employees working from home:
${d.inactiveNames.map((n, i) => `${i+1}. ${n}`).join('\n')}

For EACH active employee, generate:
1. A single emoji avatar that matches their role
2. A SHORT (10-15 words max) fun morning check-in message in first person, like a real employee greeting their boss
3. A mood: energetic | focused | creative | analytical | vigilant | cheerful

The Chief of Staff should sound authoritative and managerial.
The Gmail/Outlook Secretary should sound organised and professional.
The Content Analyst should sound creative and trend-aware.
The Crypto Specialist should sound sharp and market-aware.
The Verification Code Monitor should sound vigilant and precise.
The GitHub Alert Receiver should sound technical and alert.
The Universal Catch-All should sound dependable and reassuring.
The Finance Assistant should sound numbers-focused.
The Health Monitor should sound caring and watchful.

Return ONLY valid JSON:
{"team": [{"name": "exact workflow name", "avatar": "single emoji", "message": "check-in message", "mood": "mood"}]}

Include ALL ${d.activeNames.length} active employees.`;

return [{json: {prompt, inactiveNames: d.inactiveNames, totalActive: d.totalActive, totalInactive: d.totalInactive}}];

const raw = $input.first().json.candidates[0].content.parts[0].text;
let parsed;
try {
  const extracted = (raw.match(/\{[\s\S]*\}/) || [raw])[0];
  parsed = JSON.parse(extracted);
} catch(e) { parsed = {team: []}; }

const team = parsed.team || [];
const promptData = $('RC Build Roll Call Prompt').first().json;
const inactiveNames = promptData.inactiveNames || [];
const totalActive = promptData.totalActive || team.length;
const totalInactive = promptData.totalInactive || inactiveNames.length;

const moodColors = {
  energetic: '#1e90ff', focused: '#7c4dff', creative: '#e91e8c',
  analytical: '#00c851', vigilant: '#ff6d00', cheerful: '#ffbb33'
};

const makeCard = (avatar, name, statusBadge, statusColor, message, borderColor) => {
  const shortName = name.length > 22 ? name.substring(0, 22) + '…' : name;
  return `<td style="padding:8px;vertical-align:top;">
    <div style="background:white;border-radius:14px;padding:18px 14px;box-shadow:0 3px 14px rgba(0,0,0,0.09);border-top:4px solid ${borderColor};width:155px;text-align:center;">
      <div style="font-size:34px;margin-bottom:9px;">${avatar}</div>
      <div style="font-size:10px;font-weight:bold;color:#444;text-transform:uppercase;letter-spacing:0.7px;margin-bottom:7px;line-height:1.3;">${shortName}</div>
      <div style="background:${statusColor};font-size:10px;font-weight:bold;padding:2px 9px;border-radius:20px;margin-bottom:10px;display:inline-block;">${statusBadge}</div>
      <div style="font-size:12px;color:#666;font-style:italic;line-height:1.5;">${message}</div>
    </div>
  </td>`;
};

const activeCards = team.map(e =>
  makeCard(
    e.avatar || '🤖',
    e.name,
    '✅ IN OFFICE',
    '#e8f5e9;color:#2e7d32',
    `"${e.message}"`,
    moodColors[e.mood] || '#1e90ff'
  )
).join('');

const inactiveCards = inactiveNames.map(name =>
  makeCard('😴', name, '🏠 WFH TODAY', '#fff3e0;color:#e65100', '"Dormant — ping me via Chief of Staff!"', '#ddd')
).join('');

const now = new Date();
const html = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
