    <div style="font-size:56px;margin-bottom:14px;">🏢</div>
    <h1 style="margin:0;font-size:24px;letter-spacing:4px;font-weight:900;text-transform:uppercase;">Team Roll Call</h1>
    <p style="margin:10px 0 4px;opacity:0.75;font-size:15px;">${now.toLocaleDateString('en-GB', {weekday:'long', day:'numeric', month:'long', year:'numeric'})}</p>
    <p style="margin:0;opacity:0.5;font-size:13px;">Morning check-in · Reported by 🧑🏾 Chief of Staff</p>
  </div>

