      <td style="text-align:center;padding:12px;border-left:1px solid #eee;border-right:1px solid #eee;"><div style="font-size:36px;font-weight:900;color:#ff9800;">${totalInactive}</div><div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px;margin-top:4px;">WFH / Dormant</div></td>
