    </tr></table>
  </div>

  <div style="background:white;padding:28px 30px;">
    <div style="font-size:11px;font-weight:bold;color:#333;text-transform:uppercase;letter-spacing:2px;margin-bottom:22px;padding-bottom:12px;border-bottom:2px solid #eef2f7;">🟢 Active Team — Checked In &amp; Ready</div>
    <table cellpadding="0" cellspacing="0"><tr>${activeCards}</tr></table>
