    <div style="font-size:11px;font-weight:bold;color:#aaa;text-transform:uppercase;letter-spacing:2px;margin:32px 0 22px;padding-bottom:12px;border-bottom:2px solid #eef2f7;">🏠 Working From Home Today</div>
    <table cellpadding="0" cellspacing="0"><tr>${inactiveCards}</tr></table>` : ''}
  </div>

  <div style="background:linear-gradient(135deg,#0f3460,#16213e);color:white;padding:16px 28px;border-radius:0 0 18px 18px;font-size:12px;">
    <table width="100%" cellpadding="0" cellspacing="0"><tr>
      <td>🧑🏾 Chief of Staff · Super-Agent HQ</td>
      <td style="text-align:right;opacity:0.45;">${now.toISOString()}</td>
    </tr></table>
  </div>
</div></body></html>`;

const day = now.toLocaleDateString('en-GB', {weekday:'short', day:'numeric', month:'short'});
return [{json: {
  subject: `🏢 Team Roll Call — ${day} · ${totalActive} in office, ${totalInactive} WFH`,
  body: html,
  team_count: team.length,
  inactive_count: inactiveNames.length,
  summary: `${totalActive} in office, ${totalInactive} WFH`
}}];

